import React, { useState, useEffect, useRef } from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faHome, faComments, faHeadset } from '@fortawesome/free-solid-svg-icons';

const ChatWidget: React.FC = () => {
  const [chatOpen, setChatOpen] = useState(false);
  const [mode, setMode] = useState<'home' | 'chat'>('home');
  const [messages, setMessages] = useState([
    { from: 'admin', text: '고객님 반갑습니다!\n상담 운영 시간 안내\n· 평일 10:00 ~ 17:00\n· 주말, 공휴일 휴무\n순차적으로 확인하여 답변드리도록 하겠습니다.' }
  ]);
  const [input, setInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatOpen && mode === 'chat' && chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, chatOpen, mode]);

  const handleSend = () => {
    if (!input.trim()) return;
    setMessages(msgs => [...msgs, { from: 'user', text: input }]);
    setInput('');
    setTimeout(() => {
      setMessages(msgs => [...msgs, { from: 'admin', text: '상담 운영팀이 곧 답변드리겠습니다.' }]);
    }, 1200);
  };

  const handleOpen = () => {
    setChatOpen(true);
    setMode('home');
  };

  const handleClose = () => {
    setChatOpen(false);
    setMode('home');
  };

  return (
    <>
      {/* 문의하기 플로팅 버튼 */}
      <button
        className="fixed bottom-6 right-6 z-50 bg-blue-600 text-white rounded-full shadow-lg w-16 h-16 flex items-center justify-center text-3xl hover:bg-blue-700 transition"
        onClick={handleOpen}
        aria-label="문의하기"
        style={{ boxShadow: '0 4px 24px rgba(0,0,0,0.15)' }}
      >
        <span>💬</span>
      </button>
      {/* 문의하기 채팅 위젯 모달 */}
      {chatOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-end bg-black/10">
          <div className="w-full max-w-sm bg-white rounded-2xl shadow-2xl m-6 flex flex-col" style={{ height: '540px' }}>
            {/* 상단바 */}
            <div className="flex items-center justify-between px-6 py-6 border-b">
              <div className="flex items-center">
                <div className="w-8 h-8 rounded-full flex items-center justify-center mr-2">
                  <img src="/images/icon_admore.png" alt="logo" className="w-full h-full" />
                </div>
                <span className="font-bold text-gray-900 text-xl">애드모어 운영팀</span>
              </div>
              <button onClick={handleClose} className="text-gray-400 hover:text-gray-700 text-2xl">×</button>
            </div>
            {/* 본문: 안내/문의 or 채팅 */}
            <div className="flex-1 flex flex-col">
              {mode === 'home' ? (
                <>
                  <div className="flex-1 overflow-y-auto px-4 py-4 bg-gray-50">
                    <div className="flex flex-col items-center justify-center">
                      <div className="bg-gray-50 rounded-lg p-4 mb-4 text-sm text-gray-700">
                        <div className="font-bold mb-1">고객님 반갑습니다 <span className='text-orange-500'>🤩🤩</span></div>
                        <div className="mb-1">상담 운영 시간 안내</div>
                        <div className="mb-1">· 평일 10:00 ~ 17:00</div>
                        <div className="mb-1">· 주말, 공휴일 휴무</div>
                        <div className="mb-1">빠른 시간 내 순차적으로 확인하여 <br /> 답변드리도록 하겠습니다.</div>
                      </div>
                      <button className="w-full bg-orange-600 text-white py-3 rounded-lg font-semibold text-base mb-4 hover:bg-orange-700 transition" onClick={() => setMode('chat')}>문의하기</button>
                    </div>

                    <div className="flex items-center gap-2 mb-2 mt-4">
                      <input type="tel" className="flex-1 px-3 py-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 
                      focus:ring-orange-500 text-sm" placeholder="휴대폰 번호를 입력해 주세요." />
                      <button className="bg-orange-100 text-orange-600 px-4 py-2 rounded-md font-semibold text-xs 
                        hover:bg-orange-200 transition">SMS <br /> 등록</button>
                    </div>
                    <div className="text-xs text-gray-500 mb-2">* SMS 등록하시면 답변을 SMS로도 받아보실 수 있어요!</div>
                  </div>
                </>
              ) : (
                <>
                  <div className="flex-1 overflow-y-auto px-4 py-3 bg-gray-50">
                    {messages.map((msg, idx) => (
                      <div key={idx} className={`mb-3 flex ${msg.from === 'user' ? 'justify-end' : 'justify-start'} items-start`}>
                        {msg.from === 'admin' && (
                          <span className="w-6 h-6 rounded-full mt-1 mr-2 p-4 flex items-center justify-center bg-gray-100 border border-gray-200">
                            <FontAwesomeIcon icon={faHeadset} className="text-xl text-gray-500" />
                          </span>
                        )}
                        <div className={`rounded-xl px-4 py-2 text-sm whitespace-pre-line ${msg.from === 'user' ? 'bg-orange-600 text-white' : 'bg-white border text-gray-800'}`}>{msg.text}</div>
                      </div>
                    ))}
                  </div>
                  {/* 입력창 */}
                  <form className="flex items-center border-t px-3 py-2 gap-2" onSubmit={e => { e.preventDefault(); handleSend(); }}>
                    <input
                      type="text"
                      className="flex-1 px-3 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500 text-sm"
                      placeholder="메시지를 입력해 주세요."
                      value={input}
                      onChange={e => setInput(e.target.value)}
                      autoFocus
                    />
                    <button type="submit" className="bg-orange-600 text-white px-4 py-2 rounded-md font-semibold text-sm hover:bg-orange-700 transition">전송</button>
                  </form>
                </>
              )}
            </div>
            {/* 하단 네비게이션 탭 */}
            <div className="flex border-t divide-x">
              <button
                className={`flex-1 py-3 flex flex-col items-center text-sm font-semibold ${mode === 'home' ? 'text-orange-600' : 'text-gray-500'}`}
                onClick={() => setMode('home')}
              >
                <FontAwesomeIcon icon={faHome} className="text-sm mb-1" />
                <span className="text-xs">홈</span>
              </button>
              <button
                className={`flex-1 py-3 flex flex-col items-center text-sm font-semibold ${mode === 'chat' ? 'text-orange-600' : 'text-gray-500'}`}
                onClick={() => setMode('chat')}
              >
                <FontAwesomeIcon icon={faComments} className="text-sm mb-1" />
                <span className="text-xs">대화</span>
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default ChatWidget;
